var BIOME_RULES = {
  "volkus": {
    name:"Volkus",
    rules:[
      {name:"Condensed Stronghold", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Whenever an operative is shooting with a weapon that has the Blast, Torrent and/or x\" Devastating (i.e. Devastating with a distance requirement) weapon rule, it also has the Lethal 5+ weapon rule if the target is wholly within a stronghold terrain feature and on the killzone floor or a fire step.</li></ul>"},
      {name:"Garrisoned Stronghold", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">When an operative wholly within a stronghold terrain feature is retaliating against an operative that isn't, the defender resolves first (this takes precedence over the normal fight resolution order).</li></ul>"},
    ],
    actions:[
      {name:"Door Fight", ap:"1AP", desc:"Fight with the active operative (see fight sequence). In the Select Enemy Operative step, instead select an enemy operative on the killzone floor and within 2\" of, and on the other side of, a door the active operative is touching. For the duration of that action, those operatives are treated as being within each other's control range.", restrict:"This action is treated as a Fight action. An operative cannot perform this action while within control range of an enemy operative, or if its base isn't touching a door."},
    ],
  },
  "gallowdark": {
    name:"Gallowdark",
    rules:[
      {name:"Condensed Environment", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Weapons with the Blast, Torrent and/or x\" Devastating (i.e. Devastating with a distance requirement) weapon rule also have the Lethal 5+ weapon rule.</li></ul>"},
    ],
    actions:[
      {name:"Guard", ap:"1AP", desc:"The operative goes on guard until any of the following are true:<ul class=\"desc-list\"><li class=\"desc-green\">It performs any action, moves or is set up.</li><li class=\"desc-green\">An enemy operative ends an action within its control range and you don't interrupt that activation (see On Guard).</li><li class=\"desc-green\">Its order is changed.</li><li class=\"desc-green\">It's the start of the next turning point.</li></ul>", restrict:"This action is treated as a Shoot action. An operative cannot perform this action while it has a Conceal order, or while it's within control range of an enemy operative.", sub:{name:"On Guard", desc:"<p>Once during each enemy operative's activation, after it performs an action, you can interrupt that activation and select one friendly operative on guard to perform the Fight or Shoot action for free (including actions treated as such, e.g. Hatchway Fight). That operative then cannot counteract during the turning point.</p><p>Determine the target as normal — you don't have to target the operative you interrupted.</p><p>That operative can even Shoot while within control range of an enemy (point-blank shot):</p><ul class=\"desc-list\"><li class=\"desc-green\">Target the enemy operative within control range (even if it wouldn't normally be a valid target).</li><li class=\"desc-green\">Worsen the Hit stat of the weapon by 1.</li><li class=\"desc-green\">Until the end of the interrupted activation, your operative cannot retaliate.</li></ul>"}},
      {name:"Hatchway Fight", ap:"1AP", desc:"Fight with the active operative (see fight sequence). In the Select Enemy Operative step, instead select an enemy operative within 2\" of, and on the other side of, an open hatchway's access point the active operative is touching. For the duration of that action, those operatives are treated as being within each other's control range.", restrict:"This action is treated as a Fight action. An operative cannot perform it while within control range of an enemy operative, or if its base isn't touching an open hatchway's access point."},
      {name:"Operate Hatch", ap:"1AP", desc:"Open or close a hatchway whose access point is within the operative's control range. An operative can perform this during a Dash or Reposition action, and any remaining move distance can be used afterwards.", restrict:"An operative cannot perform this action while within control range of an enemy operative, or if that hatchway is open and its access point is within an enemy operative's control range."},
    ],
  },
  "tombworld": {
    name:"Tomb World",
    rules:[
      {name:"Condensed Environment", desc:"<ul class=\"desc-list\"><li class=\"desc-green\">Weapons with the Blast, Torrent and/or x\" Devastating (i.e. Devastating with a distance requirement) weapon rule also have the Lethal 5+ weapon rule.</li></ul>"},
    ],
    actions:[
      {name:"Guard", ap:"1AP", desc:"The operative goes on guard until any of the following are true:<ul class=\"desc-list\"><li class=\"desc-green\">It performs any action, moves or is set up.</li><li class=\"desc-green\">An enemy operative ends an action within its control range and you don't interrupt that activation (see On Guard).</li><li class=\"desc-green\">Its order is changed.</li><li class=\"desc-green\">It's the start of the next turning point.</li></ul>", restrict:"This action is treated as a Shoot action. An operative cannot perform this action while it has a Conceal order, or while it's within control range of an enemy operative.", sub:{name:"On Guard", desc:"<p>Once during each enemy operative's activation, after it performs an action, you can interrupt that activation and select one friendly operative on guard to perform the Fight or Shoot action for free (including actions treated as such, e.g. Hatchway Fight). That operative then cannot counteract during the turning point.</p><p>Determine the target as normal — you don't have to target the operative you interrupted.</p><p>That operative can even Shoot while within control range of an enemy (point-blank shot):</p><ul class=\"desc-list\"><li class=\"desc-green\">Target the enemy operative within control range (even if it wouldn't normally be a valid target).</li><li class=\"desc-green\">Worsen the Hit stat of the weapon by 1.</li><li class=\"desc-green\">Until the end of the interrupted activation, your operative cannot retaliate.</li></ul>"}},
      {name:"Hatchway Fight", ap:"1AP", desc:"Fight with the active operative (see fight sequence). In the Select Enemy Operative step, instead select an enemy operative within 2\" of, and on the other side of, an open hatchway's access point the active operative is touching. For the duration of that action, those operatives are treated as being within each other's control range.", restrict:"This action is treated as a Fight action. An operative cannot perform it while within control range of an enemy operative, or if its base isn't touching an open hatchway's access point."},
      {name:"Operate Hatch", ap:"1AP", desc:"Open or close a hatchway whose access point is within the operative's control range. An operative can perform this during a Dash or Reposition action, and any remaining move distance can be used afterwards.", restrict:"An operative cannot perform this action while within control range of an enemy operative, or if that hatchway is open and its access point is within an enemy operative's control range."},
      {name:"Breach", ap:"2AP", desc:"Open a closed breach point whose access point is within the operative's control range.<ul class=\"desc-list\"><li class=\"desc-green\">Reduced by 1AP (min 1AP) if the operative has 'breach marker', 'grenadier' or 'mine' on its datacard, or a weapon with Piercing 2 or Piercing Crits 2 (excluding Blast or Torrent weapons).</li><li class=\"desc-green\">Roll a D6 for each operative on the other side of the access point that has it within control range: on 4+, subtract 1 from that operative's APL until the end of its next activation and inflict damage equal to the result halved (rounding up).</li></ul>", restrict:"An operative cannot perform this action while within control range of an enemy operative, or if that breach point is already open. It cannot perform this for less than 2AP during an activation/counteraction in which it performed Charge or Shoot (or vice versa)."},
    ],
  },
};
